VALUES
  ('disabled-7fec267e-moex-00220', 'disabled-7fec267e', 'disabled-7fec267e-moex-112-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '關於人民不服行政處分之救濟，下列敘述何者正確？', '["不服國家通訊傳播委員會之行政處分，應先向行政院提起訴願後，始可 提起行政訴訟", "不服公平交易委員會之行政處分，應先向行政院提起訴願後，始可提起 行政訴訟", "公立學校職員不服學校對其所為之曠職登記，得提起行政訴訟", "不服交通監理機關之交通裁罰處分，應先向其上級機關提起訴願後，始 可提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:44+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00221', 'disabled-7fec267e', 'disabled-7fec267e-moex-112-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '衛生福利部依食品安全衛生管理法第22條第1項第10款規定「原料之容 器或外包裝，應以中文及通用符號，明顯標示下列事項：十、其他經中央 主管機關公告之事項」公告相關事項。業者甲認為該公告事項太過浮濫， 已造成營業損失。甲如何救濟？', '["該公告為對人之一般處分，甲得提起訴願請求撤銷之", "該公告為法規命令，現行行政訴訟制度並無法規審查程序", "甲得提起一般給付之訴，請求主管機關廢止該公告", "甲得類推都市計畫審查程序，以公告機關為被告，向管轄之高等行政法 院提起訴訟，請求宣告該公告無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:44+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00222', 'disabled-7fec267e', 'disabled-7fec267e-moex-112-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '下列何者非屬行政處分程序瑕疵之補正？', '["低收入戶未經申請的延長生活補貼，事後補提申請", "於訴願終結前，建管機關對駁回申請處分補記理由", "應該以證書方式作成而未給予證書，事後補發證書", "多階段行政處分，應參與之其他機關已於事後參與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:44+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00223', 'disabled-7fec267e', 'disabled-7fec267e-moex-112-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '關於國家賠償之敘述，下列何者錯誤？', '["法官因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職務 上之罪，經判決有罪確定者，有國家賠償法規定之適用", "檢察官因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職 務上之罪，經判決有罪確定者，有國家賠償法規定之適用", "警察機關以契約委託民間拖吊業者執行拖吊違規車輛，造成受拖吊車主 之損害，該車主可向執行之警察機關主張國家賠償", "甲為私法人之民間基金會，其雖受乙行政機關委託執行公權力，但因甲 為私法人，故人民不得對其主張國家賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:44+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00224', 'disabled-7fec267e', 'disabled-7fec267e-moex-112-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '關於徵收補償之憲法內涵，依照司法院解釋，下列敘述何者正確？', '["徵收處分作成後，如未於法定期限內發給補償，該處分失效", "補償與損失必須一致，故應採完全補償原則", "基於財產權之價值保障，補償方式限以金錢為之", "補償之對象，限於土地所有權人，不及於該土地之其他財產權人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:44+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
